83	/**
84	 * Phases that require worktree isolation.
85	 * Only `spec` runs in the main repo (planning-only, no file changes).
86	 * All other phases must run in the worktree because:
87	 * 1. They need to read/modify the worktree code
88	 * 2. Resuming a session created in a different cwd crashes the SDK
89	 */
90	const ISOLATED_PHASES: Phase[] = [
91	  "exec",
92	  "security-review",
93	  "testgen",
94	  "test",
95	  "qa",
96	  "loop",
97	];
