99	/**
100	 * Cold-start retry threshold in seconds.
101	 * Failures under this duration are likely Claude Code subprocess initialization
102	 * issues rather than genuine phase failures (based on empirical data: cold-start
103	 * failures consistently complete in 15-39s vs 150-310s for real work).
104	 */
105	const COLD_START_THRESHOLD_SECONDS = 60;
106	const COLD_START_MAX_RETRIES = 2;
107	
108	/**
109	 * Spec-specific retry configuration.
110	 * Spec failures have a higher failure rate (~8.6%) than other phases due to
111	 * transient GitHub API issues and rate limits. One extra retry with backoff
112	 * recovers most of these without user intervention.
113	 */
114	/** @internal Exported for testing only */
115	export const SPEC_RETRY_BACKOFF_MS = 5000;
116	/** @internal Exported for testing only */
117	export const SPEC_EXTRA_RETRIES = 1;
118	
119	export function parseQaVerdict(output: string): QaVerdict | null {
120	  if (!output) return null;
121	
122	  // Match various verdict formats:
123	  // - "### Verdict: X" (markdown header)
124	  // - "**Verdict:** X" (bold label with colon inside)
125	  // - "**Verdict:** **X**" (bold label and bold value)
126	  // - "Verdict: X" (plain)
127	  // Case insensitive, handles optional markdown formatting
128	  const verdictMatch = output.match(
129	    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
130	  );
131	
132	  if (!verdictMatch) return null;
133	
134	  // Normalize to uppercase with underscores
135	  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
136	  return verdict;
137	}
138	
139	/**
140	 * Parse condensed QA summary from QA phase output (#434).
141	 *
142	 * Handles multiple AC table formats produced by the QA skill:
143	 * - 5-column: | AC-N | source | desc | STATUS | notes |
144	 * - 4-column: | AC-N | desc | STATUS | notes |
145	 * - 3-column: | AC-N | desc | STATUS |
146	 *
147	 * Status cells may contain emoji prefixes (✅ MET), shorthand
148	 * (PARTIAL), or trailing text (MET — explanation).
149	 *
150	 * @internal Exported for testing only
151	 */
152	export function parseQaSummary(output: string): QaSummary | null {
153	  if (!output) return null;
154	
155	  // Anchored pattern: cell content starts with optional emoji, then status keyword
156	  // Uses alternation (not character class) to avoid ESLint no-misleading-character-class
157	  const STATUS_CELL =
158	    /^(?:\u2705|\u274C|\u26A0\uFE0F|\u2B50|\u2139\uFE0F|\u2753|\u2757)?\s*(MET|NOT_MET|PARTIALLY_MET|PARTIAL|PENDING|N\/A)\b/i;
159	
160	  const lines = output.split("\n");
161	  const acRows = lines.filter((line) => /^\s*\|\s*\*?\*?AC-\d+/.test(line));
162	
163	  if (acRows.length === 0) return null;
164	
165	  let acMet = 0;
166	  let acTotal = 0;
167	
168	  for (const row of acRows) {
169	    const cells = row
170	      .split("|")
171	      .map((c) => c.trim())
172	      .filter(Boolean);
173	
174	    // Scan cells right-to-left to find the status cell
175	    let found = false;
176	    for (let i = cells.length - 1; i >= 1; i--) {
177	      const match = cells[i].match(STATUS_CELL);
178	      if (match) {
179	        const status = match[1].toUpperCase();
180	        acTotal++;
181	        if (status === "MET") acMet++;
182	        found = true;
183	        break;
184	      }
185	    }
186	    // Row with AC-N but no parseable status is skipped
187	    if (!found) continue;
188	  }
189	
190	  if (acTotal === 0) return null;
191	
192	  const gaps = parseListSection(output, /\*\*(?:Issues|Gaps)/);
193	  const suggestions = parseListSection(output, /\*\*Suggestions/);
194	
195	  return { acMet, acTotal, gaps, suggestions };
196	}
197	
198	/**
199	 * Parse a markdown bullet list section, filtering out "None" variants.
200	 */
201	function parseListSection(output: string, headerPattern: RegExp): string[] {
202	  const items: string[] = [];
203	  const lines = output.split("\n");
204	
205	  let inSection = false;
206	  for (const line of lines) {
207	    if (headerPattern.test(line)) {
208	      // If the header line itself contains a bullet (inline), capture it
209	      inSection = true;
210	      continue;
211	    }
212	
213	    if (inSection) {
214	      // Section ends at next markdown header or bold label
215	      if (/^#{1,4}\s/.test(line) || /^\*\*[^*]+\*\*:/.test(line)) {
216	        break;
217	      }
218	
219	      const bulletMatch = line.match(/^\s*[-*]\s+(.+)/);
220	      if (bulletMatch) {
221	        const trimmed = bulletMatch[1].trim();
222	        // Filter "None", "None found", "None — text", etc.
223	        if (trimmed && !/^None\b/i.test(trimmed)) {
224	          items.push(trimmed);
225	        }
226	      } else if (line.trim() === "") {
227	        continue;
228	      } else {
229	        break;
230	      }
231	    }
232	  }
233	
234	  return items;
235	}
