237	/**
238	 * Format duration in human-readable format
239	 */
240	export function formatDuration(seconds: number): string {
241	  if (seconds < 60) {
242	    return `${seconds.toFixed(1)}s`;
243	  }
244	  const mins = Math.floor(seconds / 60);
245	  const secs = seconds % 60;
246	  return `${mins}m ${secs.toFixed(0)}s`;
247	}
