249	/**
250	 * Get the prompt for a phase with the issue number substituted.
251	 * Selects self-contained prompts for non-Claude agents.
252	 * Includes AGENTS.md content as context so non-Claude agents
253	 * receive project conventions and workflow instructions.
254	 *
255	 * @internal Exported for testing only
256	 */
257	export async function getPhasePrompt(
258	  phase: Phase,
259	  issueNumber: number,
260	  agent?: string,
261	  promptContext?: string,
262	): Promise<string> {
263	  const prompts =
264	    agent && agent !== "claude-code" ? AIDER_PHASE_PROMPTS : PHASE_PROMPTS;
265	  let basePrompt = prompts[phase].replace(/\{issue\}/g, String(issueNumber));
266	
267	  // Append phase-specific context (e.g., QA findings for loop phase)
268	  if (promptContext) {
269	    basePrompt += `\n\n---\n\n${promptContext}`;
270	  }
271	
272	  // Include AGENTS.md content in the prompt context for non-Claude agent compatibility.
273	  // Claude reads CLAUDE.md natively, but other agents (Aider, Codex, Gemini CLI)
274	  // rely on AGENTS.md for project context.
275	  const agentsMd = await readAgentsMd();
276	  if (agentsMd) {
277	    return `Project context (from AGENTS.md):\n\n${agentsMd}\n\n---\n\n${basePrompt}`;
278	  }
279	
280	  return basePrompt;
281	}
