283	/**
284	 * Execute a single phase for an issue using the configured AgentDriver.
285	 */
286	async function executePhase(
287	  issueNumber: number,
288	  phase: Phase,
289	  config: ExecutionConfig,
290	  sessionId?: string,
291	  worktreePath?: string,
292	  shutdownManager?: ShutdownManager,
293	  spinner?: PhaseSpinner,
294	): Promise<PhaseResult & { sessionId?: string }> {
295	  const startTime = Date.now();
296	
297	  const prompt = await getPhasePrompt(
298	    phase,
299	    issueNumber,
300	    config.agent,
301	    config.promptContext,
302	  );
303	
304	  if (config.dryRun) {
305	    // Dry run - show the prompt that would be sent, then return
306	    if (config.verbose) {
307	      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
308	      console.log(chalk.gray(`    Prompt: ${prompt}`));
309	    }
310	    return {
311	      phase,
312	      success: true,
313	      durationSeconds: 0,
314	      output: prompt,
315	    };
316	  }
317	
318	  if (config.verbose) {
319	    console.log(chalk.gray(`    Prompt: ${prompt}`));
320	    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
321	      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
322	    }
323	  }
324	
325	  // Determine working directory and environment
326	  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
327	  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
328	
329	  // Resolve file context for file-oriented drivers (e.g., Aider --file)
330	  let files: string[] | undefined;
331	  if (config.agent && config.agent !== "claude-code") {
332	    try {
333	      const output = execSync("git diff --name-only main...HEAD", {
334	        cwd,
335	        encoding: "utf-8",
336	        stdio: ["pipe", "pipe", "pipe"],
337	      }).trim();
338	      if (output) {
339	        files = output.split("\n").filter(Boolean);
340	      }
341	    } catch {
342	      // No changed files or git error — proceed without file context
343	    }
344	  }
345	
346	  // Check if shutdown is in progress
347	  if (shutdownManager?.shuttingDown) {
348	    return {
349	      phase,
350	      success: false,
351	      durationSeconds: 0,
352	      error: "Shutdown in progress",
353	    };
354	  }
355	
356	  // Create abort controller for timeout
357	  const abortController = new AbortController();
358	  const timeoutId = setTimeout(() => {
359	    abortController.abort();
360	  }, config.phaseTimeout * 1000);
361	
362	  // Register abort controller with shutdown manager for graceful shutdown
363	  // Uses add/remove to support concurrent phase execution (#404)
364	  if (shutdownManager) {
365	    shutdownManager.addAbortController(abortController);
366	  }
367	
368	  // Build environment with worktree isolation variables
369	  const env: Record<string, string> = {
370	    ...process.env,
371	    CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
372	  };
373	
374	  // Set worktree isolation environment variables
375	  if (shouldUseWorktree) {
376	    env.SEQUANT_WORKTREE = worktreePath;
377	    env.SEQUANT_ISSUE = String(issueNumber);
378	  }
379	
380	  // Set orchestration context for skills to detect they're part of a workflow
381	  // Skills can check these to skip redundant pre-flight checks
382	  env.SEQUANT_ORCHESTRATOR = "sequant-run";
383	  env.SEQUANT_PHASE = phase;
384	
385	  // Propagate issue type for skills to adapt behavior (e.g., lighter QA for docs)
386	  if (config.issueType) {
387	    env.SEQUANT_ISSUE_TYPE = config.issueType;
388	  }
389	
390	  // Pass QA context to loop phase so it doesn't need to reconstruct from GitHub (#488)
391	  if (config.lastVerdict) {
392	    env.SEQUANT_LAST_VERDICT = config.lastVerdict;
393	  }
394	  if (config.failedAcs) {
395	    env.SEQUANT_FAILED_ACS = config.failedAcs;
396	  }
397	
398	  // Track whether we're actively streaming verbose output
399	  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
400	  // (Issue #283: ora's stop() clears the current line, which can truncate output when
401	  // pause/resume is called for every chunk in rapid succession)
402	  let verboseStreamingActive = false;
403	
404	  // Safety: never resume a session when worktree isolation is active.
405	  // Even if THIS phase doesn't use the worktree, a previous phase may have
406	  // created the session there. Resuming from a different cwd crashes the SDK
407	  // (exit code 1). ISOLATED_PHASES prevents this by design, but this guard
408	  // catches edge cases (e.g. a new phase added without updating ISOLATED_PHASES).
409	  const canResume = sessionId && !worktreePath;
410	
411	  // Build AgentExecutionConfig for the driver
412	  const agentConfig: AgentExecutionConfig = {
413	    cwd,
414	    env,
415	    abortSignal: abortController.signal,
416	    phaseTimeout: config.phaseTimeout,
417	    verbose: config.verbose,
418	    mcp: config.mcp,
419	    sessionId: canResume ? sessionId : undefined,
420	    files,
421	    onOutput: config.verbose
422	      ? (text: string) => {
423	          if (!verboseStreamingActive) {
424	            spinner?.pause();
425	            verboseStreamingActive = true;
426	          }
427	          process.stdout.write(chalk.gray(text));
428	        }
429	      : undefined,
430	    onStderr: config.verbose
431	      ? (data: string) => {
432	          if (!verboseStreamingActive) {
433	            spinner?.pause();
434	            verboseStreamingActive = true;
435	          }
436	          process.stderr.write(chalk.red(data));
437	        }
438	      : undefined,
439	  };
440	
441	  // Resolve driver from config or default
442	  const driver: AgentDriver = getDriver(config.agent, {
443	    aiderSettings: config.aiderSettings,
444	  });
445	
446	  const agentResult = await driver.executePhase(prompt, agentConfig);
447	
448	  // Resume spinner after execution completes (if we paused it)
449	  if (verboseStreamingActive) {
450	    spinner?.resume();
451	  }
452	
453	  clearTimeout(timeoutId);
454	
455	  // Remove this specific abort controller from shutdown manager
456	  if (shutdownManager) {
457	    shutdownManager.removeAbortController(abortController);
458	  }
459	
460	  const durationSeconds = (Date.now() - startTime) / 1000;
461	
462	  // Map AgentPhaseResult to PhaseResult
463	  const tails = {
464	    stderrTail: agentResult.stderrTail,
465	    stdoutTail: agentResult.stdoutTail,
466	    exitCode: agentResult.exitCode,
467	  };
468	
469	  if (agentResult.success) {
470	    // For QA phase, check the verdict to determine actual success
471	    // Agent "success" just means the execution completed — we need to parse the verdict
472	    if (phase === "qa" && agentResult.output) {
473	      const verdict = parseQaVerdict(agentResult.output);
474	      const summary = parseQaSummary(agentResult.output) ?? undefined;
475	      if (
476	        verdict &&
477	        verdict !== "READY_FOR_MERGE" &&
478	        verdict !== "NEEDS_VERIFICATION"
479	      ) {
480	        return {
481	          phase,
482	          success: false,
483	          durationSeconds,
484	          error: `QA verdict: ${verdict}`,
485	          sessionId: agentResult.sessionId,
486	          output: agentResult.output,
487	          verdict,
488	          summary,
489	          ...tails,
490	        };
491	      }
492	      return {
493	        phase,
494	        success: true,
495	        durationSeconds,
496	        sessionId: agentResult.sessionId,
497	        output: agentResult.output,
498	        verdict: verdict ?? undefined,
499	        summary,
500	        ...tails,
501	      };
502	    }
503	
504	    return {
505	      phase,
506	      success: true,
507	      durationSeconds,
508	      sessionId: agentResult.sessionId,
509	      output: agentResult.output,
510	      ...tails,
511	    };
512	  }
513	
514	  return {
515	    phase,
516	    success: false,
517	    durationSeconds,
518	    error: agentResult.error,
519	    sessionId: agentResult.sessionId,
520	    ...tails,
521	  };
522	}
