524	/**
525	 * Execute a phase with automatic retry for cold-start failures and MCP fallback.
526	 *
527	 * Retry strategy:
528	 * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
529	 * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
530	 *    can fail on first run due to cold-cache issues)
531	 *
532	 * The MCP fallback is safe because MCP servers are optional enhancements, not required
533	 * for core functionality.
534	 */
535	/**
536	 * @internal Exported for testing only
537	 */
538	export async function executePhaseWithRetry(
539	  issueNumber: number,
540	  phase: Phase,
541	  config: ExecutionConfig,
542	  sessionId?: string,
543	  worktreePath?: string,
544	  shutdownManager?: ShutdownManager,
545	  spinner?: PhaseSpinner,
546	  /** @internal Injected for testing — defaults to module-level executePhase */
547	  executePhaseFn: typeof executePhase = executePhase,
548	  /** @internal Injected for testing — defaults to setTimeout-based delay */
549	  delayFn: (ms: number) => Promise<void> = (ms) =>
550	    new Promise((resolve) => setTimeout(resolve, ms)),
551	): Promise<PhaseResult & { sessionId?: string }> {
552	  // Skip retry logic if explicitly disabled
553	  if (config.retry === false) {
554	    return executePhaseFn(
555	      issueNumber,
556	      phase,
557	      config,
558	      sessionId,
559	      worktreePath,
560	      shutdownManager,
561	      spinner,
562	    );
563	  }
564	
565	  // Skip cold-start retries for `loop` phase (#488).
566	  // Loop is always a re-run after a failed QA — never a first boot.
567	  // Failures at 47-51s are genuine skill failures, not cold-start issues.
568	  // Without this guard, 2 cold-start retries + 1 MCP fallback = 3 wasted spawns per loop.
569	  const skipColdStartRetry = phase === "loop";
570	
571	  let lastResult: PhaseResult & { sessionId?: string };
572	
573	  if (skipColdStartRetry) {
574	    // Single attempt — no cold-start retry loop
575	    lastResult = await executePhaseFn(
576	      issueNumber,
577	      phase,
578	      config,
579	      sessionId,
580	      worktreePath,
581	      shutdownManager,
582	      spinner,
583	    );
584	
585	    if (lastResult.success) {
586	      return lastResult;
587	    }
588	  } else {
589	    // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
590	    for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
591	      lastResult = await executePhaseFn(
592	        issueNumber,
593	        phase,
594	        config,
595	        sessionId,
596	        worktreePath,
597	        shutdownManager,
598	        spinner,
599	      );
600	
601	      const duration = lastResult.durationSeconds ?? 0;
602	
603	      // Success → return immediately
604	      if (lastResult.success) {
605	        return lastResult;
606	      }
607	
608	      // Genuine failure (took long enough to be real work) → skip cold-start retries.
609	      // For spec phase, break to allow Phase 3 (spec-specific retry) to run.
610	      // For other phases, return immediately — no further retries.
611	      if (duration >= COLD_START_THRESHOLD_SECONDS) {
612	        if (phase === "spec") {
613	          break;
614	        }
615	        return lastResult;
616	      }
617	
618	      // Cold-start failure detected — retry
619	      if (attempt < COLD_START_MAX_RETRIES) {
620	        if (config.verbose) {
621	          console.log(
622	            chalk.yellow(
623	              `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
624	            ),
625	          );
626	        }
627	      }
628	    }
629	  }
630	
631	  // Capture the original error for better diagnostics
632	  const originalError = lastResult!.error;
633	
634	  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
635	  // This handles npx-based MCP servers that fail on first run due to cold-cache issues.
636	  // Skip for `loop` phase — MCP is never the cause of loop failures (#488).
637	  if (config.mcp && !lastResult!.success && !skipColdStartRetry) {
638	    console.log(
639	      chalk.yellow(
640	        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
641	      ),
642	    );
643	
644	    // Create config copy with MCP disabled
645	    const configWithoutMcp: ExecutionConfig = {
646	      ...config,
647	      mcp: false,
648	    };
649	
650	    const retryResult = await executePhaseFn(
651	      issueNumber,
652	      phase,
653	      configWithoutMcp,
654	      sessionId,
655	      worktreePath,
656	      shutdownManager,
657	      spinner,
658	    );
659	
660	    if (retryResult.success) {
661	      console.log(
662	        chalk.green(
663	          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
664	        ),
665	      );
666	      return retryResult;
667	    }
668	
669	    // Update lastResult for Phase 3 (spec retry)
670	    lastResult = retryResult;
671	
672	    // Non-spec phases: return original error after MCP fallback exhausted
673	    if (phase !== "spec") {
674	      return {
675	        ...lastResult!,
676	        error: originalError,
677	      };
678	    }
679	  }
680	
681	  // Phase 3: Spec-specific retry — spec has a higher transient failure rate
682	  // than other phases (~8.6%), so one extra retry with backoff recovers most cases.
683	  if (phase === "spec" && !lastResult!.success) {
684	    for (let i = 0; i < SPEC_EXTRA_RETRIES; i++) {
685	      console.log(
686	        chalk.yellow(
687	          `\n    ⟳ Spec phase failed, retrying with ${SPEC_RETRY_BACKOFF_MS}ms backoff... (spec retry ${i + 1}/${SPEC_EXTRA_RETRIES})`,
688	        ),
689	      );
690	
691	      await delayFn(SPEC_RETRY_BACKOFF_MS);
692	
693	      const specRetryResult = await executePhaseFn(
694	        issueNumber,
695	        phase,
696	        config,
697	        sessionId,
